using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class Event
{
    public int Id { get; set; }
    public string Name { get; set; }
    public int AvailableSeats { get; set; }
    public byte[] RowVersion { get; set; }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public string CustomerEmail { get; set; }
    public int Quantity { get; set; }
    public DateTime PurchaseDate { get; set; }
    public Event Event { get; set; }
}

public class EventBookingContext : DbContext
{
    public DbSet<Event> Events { get; set; }
    public DbSet<Ticket> Tickets { get; set; }

    public EventBookingContext(DbContextOptions<EventBookingContext> options) : base(options)
    {
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Event>(entity =>
        {
            entity.HasKey(e => e.Id);
            entity.Property(e => e.Name).IsRequired().HasMaxLength(200);
            entity.Property(e => e.AvailableSeats).IsRequired();
            entity.Property(e => e.RowVersion).IsRowVersion();
        });

        modelBuilder.Entity<Ticket>(entity =>
        {
            entity.HasKey(t => t.Id);
            entity.Property(t => t.CustomerEmail).IsRequired().HasMaxLength(255);
            entity.Property(t => t.Quantity).IsRequired();
            entity.Property(t => t.PurchaseDate).IsRequired();
            entity.HasOne(t => t.Event)
                  .WithMany()
                  .HasForeignKey(t => t.EventId)
                  .OnDelete(DeleteBehavior.Restrict);
        });
    }
}

public class TicketPurchaseResult
{
    public bool Success { get; set; }
    public string Message { get; set; }
    public Ticket Ticket { get; set; }
}

public class TicketBookingService
{
    private readonly EventBookingContext _context;
    private const int MaxRetries = 3;
    private const int MaxTicketsPerPurchase = 10;

    public TicketBookingService(EventBookingContext context)
    {
        _context = context ?? throw new ArgumentNullException(nameof(context));
    }

    public async Task<TicketPurchaseResult> PurchaseTicketsAsync(int eventId, string customerEmail, int quantity)
    {
        if (eventId <= 0)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Invalid event ID"
            };
        }

        if (string.IsNullOrWhiteSpace(customerEmail) || !IsValidEmail(customerEmail))
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Invalid customer email"
            };
        }

        if (quantity <= 0)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero"
            };
        }

        if (quantity > MaxTicketsPerPurchase)
        {
            return new TicketPurchaseResult
            {
                Success = false,
                Message = $"Cannot purchase more than {MaxTicketsPerPurchase} tickets at once"
            };
        }

        int retryCount = 0;
        while (retryCount < MaxRetries)
        {
            try
            {
                return await ProcessPurchaseAsync(eventId, customerEmail, quantity);
            }
            catch (DbUpdateConcurrencyException)
            {
                retryCount++;
                if (retryCount >= MaxRetries)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = "Unable to complete purchase due to high demand. Please try again."
                    };
                }
                await Task.Delay(100 * retryCount);
            }
            catch (Exception ex)
            {
                return new TicketPurchaseResult
                {
                    Success = false,
                    Message = "An error occurred while processing your purchase"
                };
            }
        }

        return new TicketPurchaseResult
        {
            Success = false,
            Message = "Purchase failed after multiple attempts"
        };
    }

    private async Task<TicketPurchaseResult> ProcessPurchaseAsync(int eventId, string customerEmail, int quantity)
    {
        using (var transaction = await _context.Database.BeginTransactionAsync(System.Data.IsolationLevel.Serializable))
        {
            try
            {
                var eventEntity = await _context.Events
                    .FirstOrDefaultAsync(e => e.Id == eventId);

                if (eventEntity == null)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = "Event not found"
                    };
                }

                if (eventEntity.AvailableSeats < quantity)
                {
                    return new TicketPurchaseResult
                    {
                        Success = false,
                        Message = $"Only {eventEntity.AvailableSeats} seats available"
                    };
                }

                eventEntity.AvailableSeats -= quantity;

                var ticket = new Ticket
                {
                    EventId = eventId,
                    CustomerEmail = customerEmail,
                    Quantity = quantity,
                    PurchaseDate = DateTime.UtcNow
                };

                _context.Tickets.Add(ticket);

                await _context.SaveChangesAsync();
                await transaction.CommitAsync();

                return new TicketPurchaseResult
                {
                    Success = true,
                    Message = "Purchase successful",
                    Ticket = ticket
                };
            }
            catch
            {
                await transaction.RollbackAsync();
                throw;
            }
        }
    }

    private bool IsValidEmail(string email)
    {
        if (string.IsNullOrWhiteSpace(email))
            return false;

        try
        {
            var addr = new System.Net.Mail.MailAddress(email);
            return addr.Address == email && email.Length <= 255;
        }
        catch
        {
            return false;
        }
    }

    public async Task<int> GetAvailableSeatsAsync(int eventId)
    {
        if (eventId <= 0)
            return 0;

        var eventEntity = await _context.Events
            .AsNoTracking()
            .FirstOrDefaultAsync(e => e.Id == eventId);

        return eventEntity?.AvailableSeats ?? 0;
    }
}